import React, { useState } from "react";

function AIChatbot() {
  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");

  function getReply() {
    const q = question.toLowerCase().trim();

    let response = "Maintain a balanced diet, regular exercise, hydration, and proper sleep.";

    if (q.includes("weight loss") || q.includes("lose weight")) {
      response = "For weight loss, do cardio 30 to 40 minutes daily and follow a calorie-controlled diet.";
    } else if (q.includes("stress")) {
      response = "For stress relief, try meditation, deep breathing, and light yoga for 15 to 20 minutes daily.";
    } else if (q.includes("muscle") || q.includes("gain muscle")) {
      response = "To gain muscle, do strength training 4 to 5 times a week and increase protein intake.";
    } else if (q.includes("sleep")) {
      response = "For better sleep, avoid screens before bed, reduce caffeine at night, and do relaxation breathing.";
    } else if (q.includes("diet")) {
      response = "A good fitness diet should include protein, fruits, vegetables, whole grains, and enough water.";
    } else if (q.includes("back pain")) {
      response = "For back pain, do gentle stretching, avoid bad posture, and try low-impact mobility exercises.";
    } else if (q.includes("knee pain")) {
      response = "For knee pain, do mobility stretches, avoid jumping, and strengthen the muscles around the knee.";
    } else if (q.includes("bmi")) {
      response = "BMI helps estimate body weight status, but it should be combined with exercise, diet, and body composition checks.";
    }

    setAnswer(response);
  }

  return (
    <div className="card">
      <h3>AI Fitness Chatbot</h3>

      <input
        type="text"
        placeholder="Ask any fitness question..."
        value={question}
        onChange={(e) => setQuestion(e.target.value)}
      />

      <button onClick={getReply}>Ask AI</button>

      {answer && <div className="advice-box">{answer}</div>}
    </div>
  );
}

export default AIChatbot;
